<script setup lang="ts">
import { computed, ref } from 'vue';
import { RefreshOutline } from '@vicons/ionicons5';
import { useToast } from '../composables/useToast';
import { api } from '../api';
import AgentIcon from '../components/agent-icon.vue';
import PageHeader from '../components/ui/PageHeader.vue';
import UiButton from '../components/ui/UiButton.vue';
import UiSpin from '../components/ui/UiSpin.vue';
import UiIcon from '../components/ui/UiIcon.vue';
import type { StatusInfo, UpdateCheckResult } from '../api';

const message = useToast();
const status = ref<StatusInfo | null>(null);
const updates = ref<UpdateCheckResult[]>([]);
const loading = ref(false);
const checking = ref(false);
const availableUpdates = computed(() => updates.value.filter(result => result.hasUpdate));
const maxTotal = computed(() => Math.max(1, ...(status.value?.agents.map(agent => agent.total) ?? [1])));
async function refresh() { loading.value = true; try { status.value = await api.getStatus(); } catch (error) { message.error(`加载 Agent 状态失败: ${(error as Error).message}`); } finally { loading.value = false; } }
async function checkUpdates() { checking.value = true; try { updates.value = (await api.checkUpdates()).results; } catch (error) { message.error(`检查更新失败: ${(error as Error).message}`); } finally { checking.value = false; } }
refresh();
</script>

<template>
  <div class="agents-workspace">
    <PageHeader eyebrow="Agent 注册表" title="Agent 状态" summary="查看可用目录、Skill 覆盖和运行状态。"><template #actions><UiButton size="sm" :loading="loading" @click="refresh"><template #icon><UiIcon :component="RefreshOutline" size="16" /></template>刷新</UiButton></template></PageHeader>
    <UiSpin :show="loading"><template v-if="status">
      <section class="registry-summary"><div class="summary-health"><i /><span><b>本地工作区运行正常</b><small>{{ status.installedAgents.length }} 个 Agent 已检测</small></span></div><dl><div><dt>技能总数</dt><dd>{{ status.skillCount }}</dd></div><div><dt>已纳管</dt><dd>{{ status.managedCount }}</dd></div><div><dt>未关联</dt><dd>{{ status.unmanagedCount }}</dd></div><div><dt>可更新</dt><dd>{{ availableUpdates.length || '—' }}</dd></div></dl></section>
      <section class="agent-registry"><div class="registry-heading"><div><p>已安装 Agent</p><h2>分发目标</h2></div><span>{{ status.agents.length }} 个已登记</span></div><div class="agent-cards"><article v-for="agent in status.agents" :key="agent.agent"><header><AgentIcon :agent-id="agent.agent" :agent-name="agent.agent" :size="36" /><div class="agent-identity"><b>{{ agent.agent }}</b><span>{{ status.installedAgents.includes(agent.agent) ? '可用' : '已检测' }}</span></div><i /></header><div class="agent-stat"><strong>{{ agent.total }}</strong><span>已安装 Skill</span></div><div class="coverage-bar"><i :style="{ width: `${agent.total / maxTotal * 100}%` }" /></div><footer><span><i />{{ agent.managed }} 个已纳管</span><span v-if="agent.unmanaged" class="warning">{{ agent.unmanaged }} 个未纳管</span><span v-else>状态正常</span></footer></article></div></section>
      <section class="update-watch"><div><p>更新监控</p><h2>{{ updates.length ? availableUpdates.length ? `${availableUpdates.length} 个 Skill 可更新` : '当前均为最新版本' : '尚未检查远程更新' }}</h2><span>只检查已关联远程来源的 Skill，不会自动写入。</span></div><button type="button" :disabled="checking" @click="checkUpdates">{{ checking ? '检查中…' : '检查更新' }}</button></section>
      <section v-if="updates.length" class="update-results"><article v-for="result in updates" :key="result.name"><b>{{ result.name }}</b><span v-if="result.isLocal">本地来源</span><span v-else-if="result.hasUpdate" class="warning">{{ result.currentVersion }} → {{ result.remoteVersion }}</span><span v-else class="success">已是最新</span></article></section>
      <footer class="repository-path"><span>中央仓库</span><code>{{ status.homeDir }}</code></footer>
    </template></UiSpin>
  </div>
</template>

