.agent-registry { margin-top: 1rem; }.registry-heading { display: flex; align-items: end; justify-content: space-between; margin-bottom: .55rem; }.registry-heading h2,.update-watch h2 { margin: .25rem 0 0; color: var(--color-ink); font-size: .84rem; letter-spacing: -.025em; }.registry-heading > span { color: var(--color-faint); font-family: var(--font-mono); font-size: .75rem; }.agent-cards { display: grid; grid-template-columns: repeat(auto-fill,minmax(14rem,1fr)); gap: .55rem; }.agent-cards > article { display: grid; gap: .75rem; border: 1px solid var(--color-rule); border-radius: var(--radius-lg); background: var(--color-paper); padding: .75rem; box-shadow: var(--shadow-xs); }.agent-cards > article:hover { border-color: var(--color-rule-strong); box-shadow: var(--shadow-sm); }.agent-cards header { display: grid; grid-template-columns: auto minmax(0,1fr) auto; align-items: center; gap: .55rem; }.agent-identity b,.agent-identity span { display: block; }.agent-identity b { color: var(--color-ink); font-size: .75rem; }.agent-identity span { margin-top: .06rem; color: var(--color-success); font-family: var(--font-mono); font-size: .75rem; }.agent-cards header > i { width: .4rem; height: .4rem; border-radius: 999px; background: var(--color-success); box-shadow: 0 0 0 3px var(--color-success-soft); }.agent-stat { display: flex; align-items: baseline; gap: .4rem; }.agent-stat strong { color: var(--color-ink); font-size: 1.25rem; letter-spacing: -.05em; }.agent-stat span { color: var(--color-muted); font-size: .75rem; }.coverage-bar { height: .25rem; overflow: hidden; border-radius: 999px; background: var(--color-paper-3); }.coverage-bar i { display: block; min-width: .2rem; height: 100%; border-radius: inherit; background: var(--color-accent); }.agent-cards footer { display: flex; justify-content: space-between; padding-top: .55rem; border-top: 1px solid var(--color-rule); color: var(--color-faint); font-family: var(--font-mono); font-size: .75rem; }.agent-cards footer s